"use client";

import {
  clamp01,
  mixOklch,
  type RemocnTheme,
  useRemocnTheme,
} from "@/lib/remocn-ui";

export type SliderThumbState = "idle" | "hover" | "press";

export interface SliderStyle {
  value: number;
  thumbScale: number;
  ringOpacity: number;
}

export interface SliderProps {
  value?: number;
  thumbState?: SliderThumbState;
  style?: SliderStyle;
  width?: number;
  showValue?: boolean;
  theme?: Partial<RemocnTheme>;
  className?: string;
}

const TRACK_HEIGHT = 8;
const THUMB_HEIGHT = 16;
const THUMB_WIDTH = 24;
const THUMB_RADIUS = THUMB_HEIGHT / 2;
const RING_WIDTH = 4;

function clampValue(value: number): number {
  return clamp01(value / 100) * 100;
}

export function sliderThumbStyle(thumbState: SliderThumbState): {
  thumbScale: number;
  ringOpacity: number;
} {
  switch (thumbState) {
    case "hover":
      return { thumbScale: 1.1, ringOpacity: 1 };
    case "press":
      return { thumbScale: 1.15, ringOpacity: 1 };
    default:
      return { thumbScale: 1, ringOpacity: 0 };
  }
}

export interface SliderStyleContext {
  track: string;
  range: string;
  thumbBg: string;
  thumbRing: string;
  ring: string;
  valueText: string;
}

export function sliderStyleContext(theme: RemocnTheme): SliderStyleContext {
  return {
    track: mixOklch(theme.input, theme.background, 0.1),
    range: theme.primary,
    thumbBg: "oklch(1 0 0)",
    thumbRing: "rgba(0, 0, 0, 0.1)",
    ring: mixOklch(theme.ring, theme.background, 0.7),
    valueText: theme.foreground,
  };
}

export function Slider({
  value = 0,
  thumbState = "idle",
  style,
  width = 320,
  showValue = false,
  theme: themeOverride,
  className,
}: SliderProps) {
  const theme = useRemocnTheme(themeOverride, "light");
  const ctx = sliderStyleContext(theme);

  const thumb = sliderThumbStyle(thumbState);
  const v: SliderStyle = style ?? {
    value,
    thumbScale: thumb.thumbScale,
    ringOpacity: thumb.ringOpacity,
  };
  const pct = clampValue(v.value);

  return (
    <div
      className={className}
      style={{
        position: "relative",
        display: "inline-flex",
        alignItems: "center",
        width,
        height: THUMB_HEIGHT,
        fontFamily:
          "var(--font-geist-sans), -apple-system, BlinkMacSystemFont, sans-serif",
      }}
    >
      {}
      <div
        style={{
          position: "relative",
          width: "100%",
          height: TRACK_HEIGHT,
          borderRadius: TRACK_HEIGHT / 2,
          background: ctx.track,
        }}
      >
        {}
        <div
          style={{
            position: "absolute",
            left: 0,
            top: 0,
            bottom: 0,
            width: `${pct}%`,
            borderRadius: TRACK_HEIGHT / 2,
            background: ctx.range,
          }}
        />
      </div>
      {}
      <div
        style={{
          position: "absolute",
          left: `${pct}%`,
          top: "50%",
          transform: `translate(-50%, -50%) scale(${v.thumbScale})`,
        }}
      >
        {}
        <div
          style={{
            position: "absolute",
            left: "50%",
            top: "50%",
            width: THUMB_WIDTH + RING_WIDTH * 2,
            height: THUMB_HEIGHT + RING_WIDTH * 2,
            transform: "translate(-50%, -50%)",
            borderRadius: THUMB_RADIUS + RING_WIDTH,
            background: ctx.ring,
            opacity: v.ringOpacity,
          }}
        />
        {}
        <div
          style={{
            position: "relative",
            width: THUMB_WIDTH,
            height: THUMB_HEIGHT,
            borderRadius: THUMB_RADIUS,
            background: ctx.thumbBg,
            boxShadow: `0 0 0 1px ${ctx.thumbRing}, 0 2px 4px rgba(0,0,0,0.18)`,
          }}
        />
        {showValue && (
          <span
            style={{
              position: "absolute",
              left: "50%",
              bottom: "100%",
              marginBottom: 8,
              transform: "translateX(-50%)",
              fontSize: 12,
              fontWeight: 500,
              fontVariantNumeric: "tabular-nums",
              color: ctx.valueText,
            }}
          >
            {Math.round(pct)}
          </span>
        )}
      </div>
    </div>
  );
}

"use client";

import { useCurrentFrame } from "remotion";
import {
  type SliderStyle,
  type SliderThumbState,
  sliderThumbStyle,
} from "@/components/remocn/slider";
import { clamp01, type EasingName, easings } from "@/lib/remocn-ui";

export interface SliderStep {
  at: number;
  value?: number;
  thumbState?: SliderThumbState;
  duration?: number;
  easing?: EasingName;
}

export const DEFAULT_DURATION = 18;

export interface SliderTransitionOptions {
  speed?: number;
  defaultDuration?: number;
}

export function tweenSliderStyle(
  a: SliderStyle,
  b: SliderStyle,
  t: number,
): SliderStyle {
  return {
    value: a.value + (b.value - a.value) * t,
    thumbScale: a.thumbScale + (b.thumbScale - a.thumbScale) * t,
    ringOpacity: a.ringOpacity + (b.ringOpacity - a.ringOpacity) * t,
  };
}

export function useSliderTransition(
  steps: SliderStep[],
  opts: SliderTransitionOptions = {},
): SliderStyle {
  const { speed = 1 } = opts;
  const raw = useCurrentFrame() * speed;
  return sliderStyleAt(steps, raw, opts);
}

function valueAt(
  steps: SliderStep[],
  raw: number,
  defaultDuration: number,
): number {
  const valueSteps = steps.filter(
    (s): s is SliderStep & { value: number } => s.value !== undefined,
  );
  if (valueSteps.length === 0) return 0;
  const first = valueSteps[0];
  if (raw <= first.at) return first.value;

  let toIndex = valueSteps.length - 1;
  for (let i = 1; i < valueSteps.length; i++) {
    if (valueSteps[i].at > raw) {
      toIndex = i;
      break;
    }
  }
  const pastLast = raw >= valueSteps[valueSteps.length - 1].at;
  const to = pastLast ? valueSteps[valueSteps.length - 1] : valueSteps[toIndex];
  const from = pastLast
    ? valueSteps[valueSteps.length - 1]
    : valueSteps[toIndex - 1];

  const dur = to.duration ?? defaultDuration;
  const ease = easings[to.easing ?? "out"];
  const start = to.at - dur;
  const t = pastLast || dur <= 0 ? 1 : ease(clamp01((raw - start) / dur));
  return from.value + (to.value - from.value) * t;
}

function thumbAt(
  steps: SliderStep[],
  raw: number,
  defaultDuration: number,
): { thumbScale: number; ringOpacity: number } {
  const thumbSteps = steps.filter(
    (s): s is SliderStep & { thumbState: SliderThumbState } =>
      s.thumbState !== undefined,
  );
  if (thumbSteps.length === 0) return sliderThumbStyle("idle");
  const first = thumbSteps[0];
  if (raw <= first.at) return sliderThumbStyle(first.thumbState);

  let toIndex = thumbSteps.length - 1;
  for (let i = 1; i < thumbSteps.length; i++) {
    if (thumbSteps[i].at > raw) {
      toIndex = i;
      break;
    }
  }
  const pastLast = raw >= thumbSteps[thumbSteps.length - 1].at;
  const to = pastLast ? thumbSteps[thumbSteps.length - 1] : thumbSteps[toIndex];
  const from = pastLast
    ? thumbSteps[thumbSteps.length - 1]
    : thumbSteps[toIndex - 1];

  const dur = to.duration ?? defaultDuration;
  const ease = easings[to.easing ?? "out"];
  const start = to.at - dur;
  const t = pastLast || dur <= 0 ? 1 : ease(clamp01((raw - start) / dur));

  const a = sliderThumbStyle(from.thumbState);
  const b = sliderThumbStyle(to.thumbState);
  return {
    thumbScale: a.thumbScale + (b.thumbScale - a.thumbScale) * t,
    ringOpacity: a.ringOpacity + (b.ringOpacity - a.ringOpacity) * t,
  };
}

export function sliderStyleAt(
  steps: SliderStep[],
  raw: number,
  opts: SliderTransitionOptions = {},
): SliderStyle {
  const { defaultDuration = DEFAULT_DURATION } = opts;
  const value = valueAt(steps, raw, defaultDuration);
  const thumb = thumbAt(steps, raw, defaultDuration);
  return {
    value,
    thumbScale: thumb.thumbScale,
    ringOpacity: thumb.ringOpacity,
  };
}
